<template>
    <div>
        <div class="container">
            <div class="top">
                <div class="top-inner">
                    <div class="nav">
                        <div class="logo">
                            <Logo name="校园交易" />
                        </div>
                        <div class="route">
                            <span @click="handleRouteSelect('/product')">商品</span>
                            <span v-if="loginStatus" @click="handleRouteSelect('/myProduct')">我的商品</span>
                            <span v-if="loginStatus" @click="handleRouteSelect('/mySave')">我的收藏</span>
                            <span v-if="loginStatus" @click="handleRouteSelect('/myView')">足迹</span>
                        </div>
                    </div>

                    <div class="top-actions">
                        <div class="word-search">
                            <div class="item">
                                <input type="text" placeholder="搜索商品" v-model="key">
                                <i class="el-icon-search" @click="fetch"></i>
                            </div>
                        </div>

                        <div class="action-icon" v-if="loginStatus" @click="handleRouteSelect('/orders')">
                            <i class="el-icon-document"></i>
                            <span>订单</span>
                        </div>
                        <div class="action-icon" v-if="loginStatus" @click="handleRouteSelect('/message')">
                            <i class="el-icon-bell"></i>
                            <span>通知</span>
                        </div>

                        <div class="action-primary" v-if="loginStatus" @click="handleRouteSelect('/post-product')">
                            <i class="el-icon-plus"></i>
                            <span>发布商品</span>
                        </div>

                        <div class="login-link" v-if="!loginStatus" @click="loginOperation">
                            登录&nbsp;|&nbsp;注册
                        </div>
                        <div v-else class="user-avatar">
                            <el-dropdown trigger="click">
                                <span class="user-entry">
                                    <img class="avatar" :src="userInfo.userAvatar">
                                    <span class="user-name" v-if="userInfo && userInfo.userName">
                                        {{ userInfo.userName }}
                                    </span>
                                    <i class="el-icon-arrow-down el-icon--right"></i>
                                </span>
                                <el-dropdown-menu slot="dropdown">
                                    <el-dropdown-item icon="el-icon-user-solid" @click.native="goProfile">
                                        个人中心
                                    </el-dropdown-item>
                                    <el-dropdown-item icon="el-icon-edit" @click.native="goEditProfile">
                                        修改资料
                                    </el-dropdown-item>
                                    <el-dropdown-item divided icon="el-icon-switch-button" @click.native="logout">
                                        退出登录
                                    </el-dropdown-item>
                                </el-dropdown-menu>
                            </el-dropdown>
                        </div>
                    </div>
                </div>
            </div>
            <div class="info" v-if="loginStatus">
                <div>
                    <img :src="userInfo.userAvatar" class="info-avatar">
                </div>
                <div class="info-main">
                    <div class="title1">
                        <span class="title">{{ userInfo.userName }}</span>
                        <span  class="poin" v-for="(info,index) in productInfoList" :key="index">
                            {{info.name}}·{{ info.count }}
                        </span>
                    </div>
                    <div class="date meta">
                        上一次登录时间： {{ userInfo.lastLoginTime }}
                    </div>
                    <div class="date meta">
                        注册于： {{ userInfo.createTime }}
                    </div>
                </div>
            </div>
        </div>
        <div style="padding: 10px 300px;">
            <router-view></router-view>
        </div>
    </div>
</template>
<script>
import Logo from "@/components/Logo";
import { getToken, setUserInfo, setSearchKey, clearToken } from "@/utils/storage";
export default {
    name: "Home",
    components: {
        Logo,
    },
    data() {
        return {
            selfPath: { name: '个人中心', path: '/mySelf' },
            userRoutes: [],
            key: null,
            dialogOperaion: false,
            loginStatus: false, // 默认未登录
            userInfo: {},
            searchPath: '/search',
            productInfoList: []
        };
    },
    created() {
        // 只加载登录状态和用户信息，不做任何路由强制跳转
        this.loadLoginStatus();
    },
    methods: {
        queryProductInfo() {
            this.$axios.post(`/product/queryProductInfo`, {}).then(res => {
                const { data } = res;
                if (data.code === 200) {
                    this.productInfoList = data.data;
                }
                this.loginStatus = data.code === 200;
            }).catch(error => {
                console.log("商品指标查询异常：", error);
            });
        },
        // 跳转登录页
        loginOperation() {
            this.$router.push('/login');
        },
        // 搜索
        fetch() {
            setSearchKey(this.key);
            this.handleRouteSelect(this.searchPath);
        },
        // 路由切换
        handleRouteSelect(path) {
            if (this.$router.currentRoute.fullPath !== path) {
                this.$router.push(path);
            }
        },
        //判断用户是否已经登录
        loadLoginStatus() {
            const token = getToken();
            // 没登录
            if (token === null) {
                this.loginStatus = false;
                return;
            }
            this.auth();
        },
        // token检验
        auth() {
            this.$axios.get(`/user/auth`).then(res => {
                const { data } = res;
                if (data.code === 200) {
                    // 存储用户信息
                    setUserInfo(data.data);
                    this.userInfo = data.data;
                    this.queryProductInfo();
                }
                this.loginStatus = data.code === 200;
            }).catch(error => {
                console.log("token检验异常：", error);
            });
        },
        goProfile() {
            // 进入个人中心-修改资料
            this.handleRouteSelect('/myself?tab=info');
        },
        goEditProfile() {
            // 显式进入修改资料页，便于后续扩展其他 Tab
            this.handleRouteSelect('/myself?tab=edit');
        },
        logout() {
            clearToken();
            sessionStorage.setItem('userInfo', null);
            this.loginStatus = false;
            this.$router.push('/login');
        },
    }
};
</script>
<style scoped lang="scss">
.top-inner{
    width: 100%;
    max-width: 1180px;
    margin: 0 auto;
    padding: 0 24px;
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 18px;
}

.avatar {
    border: 2px solid rgba(255,255,255,0.18);
    width: 32px;
    height: 32px;
    border-radius: 50%;
    object-fit: cover;
    box-sizing: border-box;
}

.avatar:hover {
    border: 2px solid rgba(255, 209, 80, 0.9);
}

.top-actions{
    display: flex;
    align-items: center;
    gap: 14px;
    color: rgb(143, 143, 143);
    flex: 0 0 auto;
}
.action-icon{
    cursor: pointer;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    width: 44px;
    gap: 4px;
    user-select: none;
    color: rgb(143, 143, 143);

    i{
        font-size: 18px;
        line-height: 18px;
    }
    span{
        font-size: 12px;
        line-height: 12px;
    }
}
.action-icon:hover{
    color: rgb(255, 255, 255);
}
.action-primary{
    cursor: pointer;
    display: inline-flex;
    align-items: center;
    gap: 6px;
    padding: 8px 12px;
    border-radius: 999px;
    background: rgba(255, 209, 80, 0.92);
    color: rgb(51, 51, 51);
    font-size: 14px;
    font-weight: 700;
    user-select: none;
    white-space: nowrap;

    i{
        font-size: 16px;
    }
}
.action-primary:hover{
    background: rgba(255, 209, 80, 1);
}
.login-link{
    cursor: pointer;
    user-select: none;
}
.login-link:hover{
    color: rgb(255, 255, 255);
}
.user-avatar{
    display: flex;
    align-items: center;
}
.user-entry{
    display: inline-flex;
    align-items: center;
    gap: 6px;
    cursor: pointer;
    color: rgb(245,245,245);
}
.user-name{
    max-width: 120px;
    font-size: 13px;
    white-space: nowrap;
    text-overflow: ellipsis;
    overflow: hidden;
}

.word-search {
    display: flex;
    justify-content: center;

    .item {
        max-width: 210px;
        background-color: rgb(244, 244, 244);
        border-radius: 20px;
        display: flex;
        justify-content: space-between;
        align-items: center;
        box-sizing: border-box;
        border: 1px solid rgb(245, 245, 245);

        input:focus {
            width: 110px;
        }

        input {
            border: none;
            transition: all 0.6s;
            width: 140px;
            margin: 0 10px;
            background-color: rgb(244, 244, 244);
            outline: none;
            font-size: 14px;
        }

        i {
            padding: 6px 12px;
            border-radius: 5px;
            cursor: pointer;
            border-top-right-radius: 20px;
            border-bottom-right-radius: 20px;
            background-color: rgb(244, 244, 244);
        }

        i:hover {
            background-color: rgb(241, 241, 241);
        }
    }

}

.container {
    background-color: rgb(51, 51, 51);
}

.info {
    width: 100%;
    max-width: 1180px;
    margin: 0 auto;
    padding: 10px 24px 16px 24px;
    display: flex;
    align-items: center;
    gap: 14px;

    .info-avatar{
        width: 56px;
        height: 56px;
        border-radius: 50%;
        object-fit: cover;
        padding: 3px;
        box-sizing: border-box;
        border: 2px solid rgba(255,255,255,0.85);
        background: rgba(255,255,255,0.08);
    }

    .info-main{
        padding: 0;
        min-width: 0;
    }

    .title1 {
        font-size: 20px;
        color: rgb(255, 255, 255);
        gap: 12px;

        .poin {
            display: inline-block;
            padding: 2px 6px;
            margin-inline: 4px;
            box-sizing: border-box;
            border-radius: 20px;
            cursor: pointer;
            font-size: 10px;
            color: rgb(255, 255, 255);
            background-color: rgb(197, 153, 57);
        }
    }

    .save,
    .date {
        margin: 6px 0;
        font-size: 12px;
        color: rgb(153, 150, 141);
    }
    .meta{
        opacity: 0.85;
    }

}

.top {

    height: 80px;
    display: flex;
    justify-content: center;
    align-items: center;

    .nav {
        display: flex;
        justify-content: left;
        align-items: center;
        gap: 18px;

        .route {
            display: flex;
            justify-content: left;
            align-items: center;
            gap: 18px;


            span {
                font-size: 14px;
                color: rgb(143, 143, 143);
                cursor: pointer;
            }

            span:hover {
                color: rgb(255, 255, 255);
            }
        }

    }
}
</style>